  options = '[{"id":"A","text":"and her husband, Leonard Woolf; and E.M. Forster; and painter Vanessa Bell.","is_correct":false,"explanation":"Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"and her husband, Leonard Woolf, and E.M. Forster, and painter Vanessa Bell.","is_correct":true,"explanation":"Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"and her husband, Leonard Woolf; and E.M. Forster; and, painter Vanessa Bell.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"and her husband, Leonard Woolf, and E.M. Forster, and painter Vanessa Bell","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The correct way to punctuate a series of three or more items is to use a comma after each item except the last.  A comma should precede the conjunction "and" before the last item. The passage states that "In the early twentieth century, an influential group of artists known as the Bloomsbury Group, often gathered in London …", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: and her husband, Leonard Woolf, and E.M. Forster, and painter Vanessa Bell.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
  source_metadata = COALESCE(source_metadata, '{}'::jsonb) || '{"section":"english","skill_id":"BOU","domain_id":"conventions","opensat_index":1127,"opensat_domain":"Standard English Conventions","opensat_raw_id":"random_id_c2","opensat_difficulty":"Easy","english_content_v2":true,"english_content_upgraded_at":"2026-06-12T20:01:56.882Z","english_content_upgrade_method":"upgrade-english-content.mjs"}'::jsonb,
