UPDATE public.questions SET
  stimulus_text = 'The most important thing to remember about writing is to be clear.  You should always write in a way that is easy for the reader to understand.  For example, avoid using jargon or technical terms that the reader might not be familiar with, and make sure that your sentences are well-constructed and grammatically correct.  How do you write clearly? Subsequent paragraphs reinforce the same line of reasoning with additional examples, helping readers see how the author connects specific observations to a general claim without overstating certainty.',
  question_text = 'Which choice provides the best punctuation for the sentence:  “For example, avoid using jargon or technical terms that the reader might not be familiar with, and make sure that your sentences are well-constructed and grammatically correct”?',
